import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"Initial Connect State Machine Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"zh/initial-connect-state-machine-analysis.md","filePath":"zh/initial-connect-state-machine-analysis.md"}'),n={name:"zh/initial-connect-state-machine-analysis.md"};function s(l,e,r,d,c,p){return a(),i("div",null,e[0]||(e[0]=[o(`<h1 id="initial-connect-state-machine-analysis" tabindex="-1">Initial Connect State Machine Analysis <a class="header-anchor" href="#initial-connect-state-machine-analysis" aria-label="Permalink to &quot;Initial Connect State Machine Analysis&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This document analyzes QGroundControl&#39;s vehicle initial connection pipeline implemented in:</p><ul><li><code>src/Vehicle/InitialConnectStateMachine.h</code></li><li><code>src/Vehicle/InitialConnectStateMachine.cc</code></li></ul><p>It also covers upstream/downstream dependencies that influence behavior:</p><ul><li><code>src/Vehicle/Vehicle.cc</code></li><li><code>src/Vehicle/ComponentInformation/ComponentInformationManager.*</code></li><li><code>src/Utilities/StateMachine/*</code></li><li><code>src/FirmwarePlugin/FirmwarePlugin.cc</code></li><li><code>src/FactSystem/ParameterManager.cc</code></li><li><code>src/MissionManager/GeoFenceManager.cc</code></li><li><code>src/MissionManager/RallyPointManager.cc</code></li><li><code>src/API/QGCOptions.h</code></li></ul><hr><h2 id="_1-what-the-initial-connect-state-machine-does" tabindex="-1">1. What the Initial Connect State Machine does <a class="header-anchor" href="#_1-what-the-initial-connect-state-machine-does" aria-label="Permalink to &quot;1. What the Initial Connect State Machine does&quot;">​</a></h2><p>At first online vehicle connection, QGC runs a linear state machine to gather critical vehicle metadata and synchronize mission-related state.</p><h3 id="state-order" tabindex="-1">State order <a class="header-anchor" href="#state-order" aria-label="Permalink to &quot;State order&quot;">​</a></h3><ol><li><strong>Request AUTOPILOT_VERSION</strong> (<code>RetryableRequestMessageState</code>)</li><li><strong>Request Standard Modes</strong> (<code>AsyncFunctionState</code>)</li><li><strong>Request Component Information</strong> (<code>AsyncFunctionState</code>)</li><li><strong>Request Parameters</strong> (<code>AsyncFunctionState</code>)</li><li><strong>Request Mission</strong> (<code>SkippableAsyncState</code>)</li><li><strong>Request Geofence</strong> (<code>SkippableAsyncState</code>)</li><li><strong>Request Rally Points</strong> (<code>SkippableAsyncState</code>)</li><li><strong>Signal Complete</strong> (<code>RetryState</code> with zero retries)</li><li><strong>Final</strong> (<code>QGCFinalState</code>)</li></ol><p>The state machine is started from <code>Vehicle</code> construction for normal vehicles.</p><hr><h2 id="_2-progress-model" tabindex="-1">2. Progress model <a class="header-anchor" href="#_2-progress-model" aria-label="Permalink to &quot;2. Progress model&quot;">​</a></h2><p>The machine uses weighted progress:</p><ul><li>AutopilotVersion: 1</li><li>StandardModes: 1</li><li>ComponentInfo: 5</li><li>Parameters: 5</li><li>Mission: 2</li><li>GeoFence: 1</li><li>RallyPoints: 1</li><li>Complete: 1</li></ul><p>This means parameter and component-info stages dominate progress reporting (as intended), while mission/fence/rally are lighter-weight contributors.</p><p>Sub-progress is wired from managers during long operations:</p><ul><li><code>ComponentInformationManager::progressUpdate</code></li><li><code>ParameterManager::loadProgressChanged</code></li><li><code>MissionManager::progressPctChanged</code></li><li><code>GeoFenceManager::progressPctChanged</code></li><li><code>RallyPointManager::progressPctChanged</code></li></ul><hr><h2 id="_3-retries-timeouts-and-failure-behavior" tabindex="-1">3. Retries/timeouts and failure behavior <a class="header-anchor" href="#_3-retries-timeouts-and-failure-behavior" aria-label="Permalink to &quot;3. Retries/timeouts and failure behavior&quot;">​</a></h2><h3 id="per-state-retry-policy" tabindex="-1">Per-state retry policy <a class="header-anchor" href="#per-state-retry-policy" aria-label="Permalink to &quot;Per-state retry policy&quot;">​</a></h3><p><code>_maxRetries = 1</code> globally for initial connect states.</p><p>Timeouts:</p><ul><li>AUTOPILOT_VERSION: 5000 ms</li><li>StandardModes: 5000 ms</li><li>ComponentInfo: 30000 ms</li><li>Parameters: 60000 ms</li><li>Mission: 30000 ms</li><li>GeoFence: 15000 ms</li><li>RallyPoints: 15000 ms</li></ul><h3 id="important-semantic-detail" tabindex="-1">Important semantic detail <a class="header-anchor" href="#important-semantic-detail" aria-label="Permalink to &quot;Important semantic detail&quot;">​</a></h3><p>For all async states after AUTOPILOT_VERSION, timeout handling uses <code>RetryTransition</code>:</p><ul><li>On first timeout: retry in-place (<code>restartWait()</code> + retry action), no state transition.</li><li>After retries exhausted: transition to the next state.</li></ul><p>So timeout exhaustion is <strong>graceful degradation</strong> (advance), not hard stop, for this machine.</p><h3 id="autopilot-version-state-behavior" tabindex="-1">AUTOPILOT_VERSION state behavior <a class="header-anchor" href="#autopilot-version-state-behavior" aria-label="Permalink to &quot;AUTOPILOT_VERSION state behavior&quot;">​</a></h3><p>AUTOPILOT_VERSION uses <code>RetryableRequestMessageState</code>, which also retries and then advances by default when retries are exhausted (<code>failOnMaxRetries</code> is not enabled here). It invokes a failure handler before advancing.</p><hr><h2 id="_4-exactly-what-is-skipped-and-when" tabindex="-1">4. Exactly what is skipped, and when <a class="header-anchor" href="#_4-exactly-what-is-skipped-and-when" aria-label="Permalink to &quot;4. Exactly what is skipped, and when&quot;">​</a></h2><h2 id="a-entire-machine-skipped" tabindex="-1">A) Entire machine skipped <a class="header-anchor" href="#a-entire-machine-skipped" aria-label="Permalink to &quot;A) Entire machine skipped&quot;">​</a></h2><p>In unit tests, the machine is <strong>not started</strong> only for synthetic generic vehicles:</p><ul><li>Condition: <code>qgcApp()-&gt;runningUnitTests() &amp;&amp; _vehicleType == MAV_TYPE_GENERIC</code></li></ul><p>All real vehicle types still run initial connect during tests.</p><h2 id="b-autopilot-version-request-skipped" tabindex="-1">B) AUTOPILOT_VERSION request skipped <a class="header-anchor" href="#b-autopilot-version-request-skipped" aria-label="Permalink to &quot;B) AUTOPILOT_VERSION request skipped&quot;">​</a></h2><p>State skip predicate returns true if:</p><ol><li>No primary link exists, <strong>or</strong></li><li>Primary link is high-latency (<code>LinkConfiguration::isHighLatency()</code>), <strong>or</strong></li><li>Primary link is log replay (<code>LinkInterface::isLogReplay()</code> true, e.g. <code>LogReplayLink</code>)</li></ol><p>When skipped, the state completes immediately and transitions to StandardModes.</p><h2 id="c-mission-load-skipped" tabindex="-1">C) Mission load skipped <a class="header-anchor" href="#c-mission-load-skipped" aria-label="Permalink to &quot;C) Mission load skipped&quot;">​</a></h2><p>Mission state is skipped if:</p><ol><li>Link type should be skipped (<code>high latency</code> or <code>log replay</code>), <strong>or</strong></li><li>No primary link</li></ol><h2 id="d-geofence-load-skipped" tabindex="-1">D) Geofence load skipped <a class="header-anchor" href="#d-geofence-load-skipped" aria-label="Permalink to &quot;D) Geofence load skipped&quot;">​</a></h2><p>Geofence state is skipped if any of:</p><ol><li>Link type should be skipped (<code>high latency</code> or <code>log replay</code>), <strong>or</strong></li><li>No primary link, <strong>or</strong></li><li><code>GeoFenceManager::supported()</code> is false <ul><li><code>supported()</code> is capability-driven: requires <code>MAV_PROTOCOL_CAPABILITY_MISSION_FENCE</code></li></ul></li></ol><h2 id="e-rally-points-load-skipped" tabindex="-1">E) Rally points load skipped <a class="header-anchor" href="#e-rally-points-load-skipped" aria-label="Permalink to &quot;E) Rally points load skipped&quot;">​</a></h2><p>Rally state is skipped if any of:</p><ol><li>Link type should be skipped (<code>high latency</code> or <code>log replay</code>), <strong>or</strong></li><li>No primary link, <strong>or</strong></li><li><code>RallyPointManager::supported()</code> is false <ul><li><code>supported()</code> requires <code>MAV_PROTOCOL_CAPABILITY_MISSION_RALLY</code></li></ul></li></ol><p>When rally is skipped, QGC still marks:</p><ul><li><code>_initialPlanRequestComplete = true</code></li><li>emits <code>initialPlanRequestCompleteChanged(true)</code></li></ul><p>so downstream UI logic does not stall waiting for rally load.</p><h2 id="f-component-information-sub-states-skipped-inside-componentinformationmanager" tabindex="-1">F) Component information sub-states skipped (inside ComponentInformationManager) <a class="header-anchor" href="#f-component-information-sub-states-skipped-inside-componentinformationmanager" aria-label="Permalink to &quot;F) Component information sub-states skipped (inside ComponentInformationManager)&quot;">​</a></h2><p><code>ComponentInformationManager</code> itself has internal skippable phases:</p><ul><li>Parameter metadata skipped if <code>GENERAL</code> metadata says parameter metadata unsupported</li><li>Events metadata skipped if unsupported</li><li>Actuators metadata skipped if unsupported</li></ul><p>Support checks are based on <code>CompInfoGeneral::isMetaDataTypeSupported(type)</code>.</p><hr><h2 id="_5-what-data-is-captured-during-initial-connect-and-why" tabindex="-1">5. What data is captured during initial connect, and why <a class="header-anchor" href="#_5-what-data-is-captured-during-initial-connect-and-why" aria-label="Permalink to &quot;5. What data is captured during initial connect, and why&quot;">​</a></h2><h2 id="a-autopilot-version-data-captured" tabindex="-1">A) AUTOPILOT_VERSION data captured <a class="header-anchor" href="#a-autopilot-version-data-captured" aria-label="Permalink to &quot;A) AUTOPILOT_VERSION data captured&quot;">​</a></h2><p>On successful AUTOPILOT_VERSION response, QGC captures:</p><ol><li><p><strong>Vehicle UID</strong> (<code>uid</code>)</p><ul><li>Used as stable identity and surfaced via <code>vehicleUIDChanged</code>.</li></ul></li><li><p><strong>Firmware board vendor/product IDs</strong></p><ul><li>Hardware identification for board-specific behavior and diagnostics.</li></ul></li><li><p><strong>Flight software semantic version</strong> (<code>flight_sw_version</code> packed fields)</p><ul><li>Parsed into major/minor/patch/version-type and stored in <code>Vehicle</code>.</li></ul></li><li><p><strong>Firmware custom version / git hash</strong></p><ul><li>PX4: decoded from binary bytes (reverse-order formatting)</li><li>APM: decoded as 8-char ASCII</li><li>Exposed via <code>gitHashChanged</code>.</li></ul></li><li><p><strong>MAVLink capability bits</strong></p><ul><li>Stored via <code>_setCapabilities(...)</code></li><li>Drives feature gating such as mission-int, command-int, geofence, rally support.</li></ul></li></ol><p>If AUTOPILOT_VERSION fails, QGC sets <strong>assumed capabilities</strong>:</p><ul><li>Always assume MAVLink2</li><li>For PX4/APM, also assume mission-int/command-int/fence/rally support</li></ul><p>This allows connect flow to continue even without that message.</p><h2 id="b-standard-modes-captured" tabindex="-1">B) Standard modes captured <a class="header-anchor" href="#b-standard-modes-captured" aria-label="Permalink to &quot;B) Standard modes captured&quot;">​</a></h2><p>QGC requests available standard modes one-by-one (<code>AVAILABLE_MODES</code>) and updates firmware plugin mode mapping.</p><p>Purpose:</p><ul><li>Provide accurate, vehicle-reported mode names/availability.</li><li>Refresh flight mode UI mapping even if HEARTBEAT arrives earlier.</li></ul><h2 id="c-component-information-captured" tabindex="-1">C) Component Information captured <a class="header-anchor" href="#c-component-information-captured" aria-label="Permalink to &quot;C) Component Information captured&quot;">​</a></h2><p><code>ComponentInformationManager</code> requests metadata in this sequence:</p><ol><li><code>GENERAL</code> metadata</li><li>URI update pass (maps/propagates discovered metadata URIs)</li><li><code>PARAMETER</code> metadata (if supported)</li><li><code>EVENTS</code> metadata (if supported)</li><li><code>ACTUATORS</code> metadata (if supported)</li></ol><h3 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h3><ul><li><strong>Parameter metadata</strong> (<code>CompInfoParam</code>) feeds <code>ParameterManager</code> metadata lookups (<code>factMetaDataForName</code>), affecting parameter typing/metadata behavior.</li><li><strong>Events metadata</strong> supports event schema/decoding ecosystem.</li><li><strong>Actuators metadata</strong> is used by PX4 actuator configuration UX: <ul><li>If actuator metadata is absent or actuator conditions fail, PX4 plugin falls back to legacy Motor page.</li><li>If present and valid (<code>show-ui-if</code> etc.), Actuators page is enabled.</li></ul></li></ul><p>So component info is both a data-quality improvement and a feature-availability gate.</p><h2 id="d-parameters-stage-captured" tabindex="-1">D) Parameters stage captured <a class="header-anchor" href="#d-parameters-stage-captured" aria-label="Permalink to &quot;D) Parameters stage captured&quot;">​</a></h2><ul><li>Requests full parameter refresh (<code>refreshAllParameters()</code>)</li><li>Waits for <code>parametersReadyChanged(true)</code></li><li>On ready: <ul><li>Sends GCS time to vehicle twice (reliability)</li><li>Sets up auto-disarm signalling</li></ul></li></ul><p>This stage is foundational for most setup/calibration UI and many capability/behavior branches.</p><h2 id="e-plan-data-captured" tabindex="-1">E) Plan data captured <a class="header-anchor" href="#e-plan-data-captured" aria-label="Permalink to &quot;E) Plan data captured&quot;">​</a></h2><ul><li>Mission items from vehicle</li><li>Geofence data (if supported and not skipped)</li><li>Rally points (if supported and not skipped)</li></ul><p>On rally completion (or rally skip), QGC sets initial plan load complete.</p><hr><h2 id="_6-where-check-latest-stable-firmware-fits" tabindex="-1">6. Where &quot;check latest stable firmware&quot; fits <a class="header-anchor" href="#_6-where-check-latest-stable-firmware-fits" aria-label="Permalink to &quot;6. Where &quot;check latest stable firmware&quot; fits&quot;">​</a></h2><p>The latest-stable firmware check is triggered as a <strong>side-effect</strong> of AUTOPILOT_VERSION success:</p><ul><li>Condition: <code>QGCOptions::checkFirmwareVersion()</code> is true and <code>_checkLatestStableFWDone</code> is false.</li><li>Action: <code>FirmwarePlugin::checkIfIsLatestStable(vehicle)</code>.</li></ul><p>This is asynchronous (downloads and parses a version file), and <strong>does not gate</strong> state machine transitions. Initial connect continues regardless of result.</p><p>It is skipped during unit tests in <code>FirmwarePlugin::checkIfIsLatestStable</code>.</p><hr><h2 id="_7-options-configurations-that-affect-behavior" tabindex="-1">7. Options/configurations that affect behavior <a class="header-anchor" href="#_7-options-configurations-that-affect-behavior" aria-label="Permalink to &quot;7. Options/configurations that affect behavior&quot;">​</a></h2><ol><li><p><strong>Link configuration high-latency flag</strong></p><ul><li><code>LinkConfiguration.highLatency</code></li><li>Causes skipping of AUTOPILOT_VERSION and plan-load states.</li></ul></li><li><p><strong>Log replay link type</strong></p><ul><li><code>LinkInterface::isLogReplay()</code> true</li><li>Same skip effect as high-latency.</li></ul></li><li><p><strong>Firmware/version check option</strong></p><ul><li><code>QGCOptions::checkFirmwareVersion()</code> (virtual, custom-build overridable)</li><li>Controls only latest-stable check side-effect, not transition graph.</li></ul></li><li><p><strong>Capability bits</strong></p><ul><li>From AUTOPILOT_VERSION or assumed fallback.</li><li>Gate geofence/rally support and therefore skip decisions.</li></ul></li><li><p><strong>Metadata support flags from CompInfoGeneral</strong></p><ul><li>Gate internal component-info sub-requests (param/events/actuators metadata).</li></ul></li></ol><hr><h2 id="_8-practical-implications" tabindex="-1">8. Practical implications <a class="header-anchor" href="#_8-practical-implications" aria-label="Permalink to &quot;8. Practical implications&quot;">​</a></h2><ul><li>The machine is designed for <strong>robust connect</strong>, not strict fail-fast.</li><li>Network/link quality and link type strongly influence which expensive operations are skipped.</li><li>Component information is a key bridge between firmware-reported metadata and dynamic UI behavior (especially parameters and actuators).</li><li>Missing AUTOPILOT_VERSION does not block connect; QGC degrades gracefully with assumptions.</li></ul><hr><h2 id="_9-quick-skip-matrix" tabindex="-1">9. Quick skip matrix <a class="header-anchor" href="#_9-quick-skip-matrix" aria-label="Permalink to &quot;9. Quick skip matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>State</th><th>Skip trigger(s)</th><th>Outcome</th></tr></thead><tbody><tr><td>AUTOPILOT_VERSION</td><td>no primary link OR high-latency OR log replay</td><td>immediate complete/advance</td></tr><tr><td>StandardModes</td><td>none explicit</td><td>retry-on-timeout then advance</td></tr><tr><td>ComponentInfo</td><td>none explicit</td><td>retry-on-timeout then advance</td></tr><tr><td>Parameters</td><td>none explicit</td><td>retry-on-timeout then advance</td></tr><tr><td>Mission</td><td>high-latency OR log replay OR no primary link</td><td>skipped -&gt; GeoFence</td></tr><tr><td>GeoFence</td><td>mission skip conditions OR !fence capability</td><td>skipped -&gt; Rally</td></tr><tr><td>Rally</td><td>mission skip conditions OR !rally capability</td><td>skipped -&gt; Complete (+mark plan complete)</td></tr><tr><td>Complete</td><td>never skipped</td><td>emits <code>initialConnectComplete</code> at machine finish</td></tr></tbody></table><h3 id="run-matrix-by-highlatency-logreplay-flying" tabindex="-1">Run matrix by (HighLatency, LogReplay, Flying) <a class="header-anchor" href="#run-matrix-by-highlatency-logreplay-flying" aria-label="Permalink to &quot;Run matrix by (HighLatency, LogReplay, Flying)&quot;">​</a></h3><p>Assumptions for this matrix:</p><ul><li>Primary link exists</li><li>Geofence and rally are supported by capability bits</li><li>State machine is started (not the <code>runningUnitTests &amp;&amp; MAV_TYPE_GENERIC</code> bypass)</li></ul><p>Legend:</p><ul><li><code>Run</code> = state logic executes (it may still complete quickly)</li><li><code>Skip</code> = state is skipped by state skip predicate</li><li><code>Run*</code> = state executes but parameter download is short-circuited inside <code>ParameterManager</code> for high-latency/log-replay links</li></ul><table tabindex="0"><thead><tr><th>State</th><th>HL=0 LR=0 Fly=0</th><th>HL=0 LR=0 Fly=1</th><th>HL=1 LR=0 Fly=0</th><th>HL=1 LR=0 Fly=1</th><th>HL=0 LR=1 Fly=0</th><th>HL=0 LR=1 Fly=1</th><th>HL=1 LR=1 Fly=0</th><th>HL=1 LR=1 Fly=1</th></tr></thead><tbody><tr><td>AUTOPILOT_VERSION</td><td>Run</td><td>Run</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td></tr><tr><td>StandardModes</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td></tr><tr><td>ComponentInfo</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td></tr><tr><td>Parameters</td><td>Run</td><td>Run</td><td>Run*</td><td>Run*</td><td>Run*</td><td>Run*</td><td>Run*</td><td>Run*</td></tr><tr><td>Mission</td><td>Run</td><td>Run</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td></tr><tr><td>GeoFence</td><td>Run</td><td>Run</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td></tr><tr><td>Rally</td><td>Run</td><td>Run</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td><td>Skip</td></tr><tr><td>Complete</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td><td>Run</td></tr></tbody></table><p><code>Flying</code> does not currently participate in InitialConnectStateMachine skip predicates. It does not change run/skip behavior in this machine.</p><h3 id="unit-test-readable-matrix-request-expectations" tabindex="-1">Unit-test readable matrix (request expectations) <a class="header-anchor" href="#unit-test-readable-matrix-request-expectations" aria-label="Permalink to &quot;Unit-test readable matrix (request expectations)&quot;">​</a></h3><p>This is the same compact matrix used by <code>_stateRunMatrix_data</code> in <code>InitialConnectTest</code>.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+----+----+-----+------------+------------+----------------+</span></span>
<span class="line"><span>| HL | LR | Fly | AP_VERSION | AVAIL_MODS | PLAN_REQ_LISTS |</span></span>
<span class="line"><span>+----+----+-----+------------+------------+----------------+</span></span>
<span class="line"><span>| 0  | 0  | 0   | Run        | Run        | Run            |</span></span>
<span class="line"><span>| 0  | 0  | 1   | Run        | Run        | Run            |</span></span>
<span class="line"><span>| 1  | 0  | 0   | Skip       | Run        | Skip           |</span></span>
<span class="line"><span>| 1  | 0  | 1   | Skip       | Run        | Skip           |</span></span>
<span class="line"><span>| 0  | 1  | 0   | Skip       | Run        | Skip           |</span></span>
<span class="line"><span>| 0  | 1  | 1   | Skip       | Run        | Skip           |</span></span>
<span class="line"><span>| 1  | 1  | 0   | Skip       | Run        | Skip           |</span></span>
<span class="line"><span>| 1  | 1  | 1   | Skip       | Run        | Skip           |</span></span>
<span class="line"><span>+----+----+-----+------------+------------+----------------+</span></span></code></pre></div><p>Where:</p><ul><li><code>HL</code> = HighLatency</li><li><code>LR</code> = LogReplay</li><li><code>Fly</code> = Flying</li><li><code>AP_VERSION</code> = <code>AUTOPILOT_VERSION</code> request expected</li><li><code>AVAIL_MODS</code> = <code>AVAILABLE_MODES</code> request expected</li><li><code>PLAN_REQ_LISTS</code> = mission/geofence/rally <code>MISSION_REQUEST_LIST</code> traffic expected</li></ul><p>Skip behavior basis: <code>skipForLinkType = (highLatency || logReplay)</code>.</p><hr><h2 id="_10-notes-on-observability-debugging" tabindex="-1">10. Notes on observability/debugging <a class="header-anchor" href="#_10-notes-on-observability-debugging" aria-label="Permalink to &quot;10. Notes on observability/debugging&quot;">​</a></h2><p>Useful log categories for tracing behavior:</p><ul><li><code>Vehicle.InitialConnectStateMachine</code></li><li><code>ComponentInformation.ComponentInformationManager</code></li><li><code>Vehicle.StandardModes</code></li><li><code>Vehicle</code> (capability logs)</li><li><code>ActuatorsConfig</code> (for metadata-driven actuator UI decisions)</li></ul><p>This combination lets you determine:</p><ul><li>Which states were entered/skipped/timed out</li><li>Which metadata types were supported/downloaded</li><li>Why actuator UI appeared or fell back to legacy motor UI</li></ul>`,115)]))}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
